mapper.select:
select u.user_id, u.dept_id, u.user_type,u.nick_name,u.order_status, u.user_name, u.email, u.avatar, u.phone, u.password, u.sex, u.status, u.is_delete, u.login_ip, u.login_date, u.create_user, u.create_time, u.is_remind,u.remind_url,u.remark_name,u.remark_info,u.custom_status,u.custom_reply, u.remark, d.dept_name, d.leader,u.is_messages from sys_user u left join sys_department d on u.dept_id = d.dept_id where u.is_delete = 0
AND u.user_id = #{userId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.user_type = #{userType}
AND u.status = #{status}
AND u.phone like concat('%', #{phone}, '%')
AND date_format(u.create_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')
AND date_format(u.create_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')
AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_department t WHERE find_in_set(#{deptId}, ancestors) ))

mapper.update:
update sys_user
user_name = #{userName}, nick_name = #{nickName}, openid = #{openid}, email = #{email}, phone = #{phone}, avatar = #{avatar}, password = #{password}, login_ip = #{loginIp}, login_date = #{loginDate}, update_user = #{updateUser}, remark = #{remark}, user_type = #{userType}, company=#{company}, project=#{project}, area=#{area}, property=#{property}, is_remind = #{isRemind}, remind_url = #{remindUrl}, remark_name = #{remarkName}, remark_info = #{remarkInfo}, custom_status = #{customStatus}, custom_reply = #{customReply}, update_time = sysdate()
where user_id = #{userId}

update sys_user
nick_name = #{nickName}, phone = #{phone}, openid = #{openid}, avatar = #{avatar}, password = #{password}, update_user = #{updateUser}, company=#{company}, project=#{project}, area=#{area}, property=#{property}, remark_name = #{remarkName}, remark_info = #{remarkInfo}, custom_status = #{customStatus}, custom_reply = #{customReply}, update_time = sysdate()
where user_id = #{userId}

update sys_user
set smartName = #{smartName},smartPassword = #{smartPassword}
  ,smartRealName = #{smartRealName},isBindSmart = 1
where user_id = #{userId}

mapper.select:
select distinct u.user_id, u.dept_id, u.user_name, u.nick_name, u.is_remind,u.remind_url,u.remark_name,u.remark_info, u.email, u.phone, u.status, u.create_time,d.dept_name from sys_user u left join sys_dept d on u.dept_id = d.dept_id left join sys_role_user ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.is_delete = 0 and r.role_id = #{roleId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.phone like concat('%', #{phone}, '%')
